          {
            "text": "Subnet name : Enter Public_subnet_first_VPC"
          },
          {
            "text": "Availability Zone : Leave as No Preference"
          },
          {
            "text": "IPv4 CIDR block : Enter 10.0.0.0/25"
          },
          {
            "text": "Now click on the Create subnet button."
          }
